import { PrismaClient, AdviceCategory, ContentSource } from '@prisma/client';
const prisma = new PrismaClient();

/**
 * Batch 4 — Fill sparse pregnancy weeks (odd weeks 15-39, plus early weeks with <3 cards).
 *
 * The original seed had strong coverage for even-numbered pregnancy weeks but
 * left ~22 weeks with only 1-2 cards each, missing fundamental categories
 * (GROWTH_HEALTH, DEVELOPMENT, NUTRITION_FEEDING, SLEEP, PLAY_ACTIVITIES).
 * This batch adds 110 cards across 22 stageKeys averaging 5 cards/week.
 */
export async function seedPregnancyFillCards() {
  console.log('Seeding pregnancy fill-in advice cards (batch 4)...');

  const cards: Array<{
    stageKey: string;
    category: AdviceCategory;
    priority: number;
    title: string;
    summary: string;
    content: string;
    source: ContentSource;
    tags: string[];
  }> = [
    // ═══ preg_week_1 (had 1 card) ═══
    { stageKey: 'preg_week_1', category: 'NUTRITION_FEEDING', priority: 86, title: 'Preconception Nutrition: Building Your Baby\'s Foundation', summary: 'Even before conception, what you eat matters — your body is preparing the environment where your baby will grow for the next nine months.', content: 'The weeks before conception are a critical window for nutritional preparation. Folic acid is the standout nutrient — start taking 400-800 micrograms daily at least one month before trying to conceive. This B vitamin dramatically reduces neural tube defects, which form in the first 28 days of pregnancy — often before you know you are pregnant. Iron stores need to be adequate before pregnancy begins; include lean red meat, lentils, spinach, and iron-fortified cereals. Omega-3 fatty acids, especially DHA, accumulate in your body before pregnancy and are essential for fetal brain development. Limit caffeine to 200 mg daily. If you are on any medications, schedule a preconception visit with your provider to review them. Your weight matters too — being significantly underweight or overweight can affect ovulation and pregnancy outcomes.', source: 'CLINICAL' as ContentSource, tags: ['preconception', 'folic acid', 'nutrition', 'iron', 'DHA'] },
    { stageKey: 'preg_week_1', category: 'DEVELOPMENT', priority: 84, title: 'The Menstrual Cycle: Your Body\'s Monthly Preparation', summary: 'Your body has been preparing for pregnancy every cycle — understanding this rhythm helps you contextualize the weeks ahead.', content: 'A typical menstrual cycle lasts 21 to 35 days, with ovulation occurring around day 14 in a 28-day cycle. During the follicular phase, rising estrogen thickens the uterine lining, preparing a nourishing environment. Ovulation releases a mature egg, which travels through the fallopian tube. The luteal phase follows — the ruptured follicle becomes the corpus luteum, producing progesterone that maintains the uterine lining. If no fertilization occurs, hormone levels drop and menstruation begins, resetting the cycle. If you are trying to conceive, tracking your cycle through ovulation predictor kits, basal body temperature, and cervical mucus observations provides valuable information. Irregular cycles may indicate conditions like polycystic ovary syndrome and are worth discussing with your provider.', source: 'DEVELOPMENT' as ContentSource, tags: ['menstrual cycle', 'ovulation', 'follicular phase', 'luteal phase', 'conception'] },
    { stageKey: 'preg_week_1', category: 'SLEEP', priority: 80, title: 'Sleep and Fertility: The Overlooked Connection', summary: 'Your sleep quality directly affects reproductive hormones — prioritizing rest now supports your body at every stage.', content: 'Research increasingly shows that sleep quality affects fertility. Disrupted circadian rhythms and insufficient sleep can interfere with the hormonal signals that regulate ovulation. Melatonin — your sleep hormone — also plays a protective role in ovarian function and egg quality. Shift work, which chronically disrupts sleep-wake cycles, is associated with menstrual irregularities and reduced fertility. Aim for 7 to 9 hours of quality sleep per night. Establish a consistent bedtime routine. Limit screen exposure in the hour before bed — blue light suppresses melatonin production. If you work night shifts or have irregular hours, discuss strategies with your healthcare provider. Sleep is not a luxury; it is a biological necessity that supports your entire endocrine system.', source: 'DEVELOPMENT' as ContentSource, tags: ['sleep', 'fertility', 'circadian rhythm', 'melatonin', 'hormones'] },
    { stageKey: 'preg_week_1', category: 'PLAY_ACTIVITIES', priority: 78, title: 'Gentle Movement in the Preconception Window', summary: 'Movement supports hormone balance, stress reduction, and a healthy weight — all of which contribute to fertility and a healthy pregnancy.', content: 'Regular moderate exercise supports fertility by helping maintain a healthy body weight, reducing stress, and improving insulin sensitivity — all of which influence ovulation. Aim for 150 minutes of moderate activity per week: brisk walking, swimming, cycling, dancing, or prenatal yoga. If you are underweight, focus on strength-building activities and adequate caloric intake. If you are overweight, even modest weight loss of 5 to 10 percent can improve ovulatory function. Avoid extreme exercise — excessive high-intensity training can suppress ovulation, a condition sometimes called the female athlete triad. Listen to your body. The goal now is to establish sustainable movement habits that will serve you throughout pregnancy and postpartum.', source: 'DEVELOPMENT' as ContentSource, tags: ['exercise', 'fertility', 'weight management', 'ovulation', 'wellness'] },

    // ═══ preg_week_2 (had 1 card) ═══
    { stageKey: 'preg_week_2', category: 'GROWTH_HEALTH', priority: 86, title: 'Your Body at Week 2: Preparing the Nest', summary: 'Your uterine lining is thickening into a lush, blood-rich environment — your body is literally building the nest where your baby will implant.', content: 'During week two of your cycle, estrogen levels rise, signaling your uterine lining (endometrium) to thicken and become enriched with blood vessels and nutrients. On ultrasound, the endometrium develops a characteristic trilaminar, or triple-stripe, appearance — a sign of optimal receptivity. This is your body preparing the perfect environment for a fertilized egg to implant. A lining of at least 7 to 8 millimeters thickness is generally considered favorable for implantation. Factors that support endometrial health include adequate blood flow, balanced hormones, proper nutrition, and avoiding tobacco. If you have a history of thin endometrial lining or recurrent implantation challenges, your provider may recommend treatments like supplemental estrogen or medications to improve blood flow.', source: 'CLINICAL' as ContentSource, tags: ['endometrium', 'uterine lining', 'estrogen', 'implantation', 'preconception'] },
    { stageKey: 'preg_week_2', category: 'SLEEP', priority: 79, title: 'Rest as Preparation: Why Sleep Matters Right Now', summary: 'Your body is doing extraordinary work preparing for possible conception — sleep is the time when hormone regulation and cellular repair peak.', content: 'Quality sleep during the preconception window supports the complex hormonal choreography of your menstrual cycle. The hypothalamic-pituitary-ovarian axis — the communication system between your brain and ovaries — is sensitive to stress and sleep disruption. Cortisol, your primary stress hormone, normally dips at night while growth hormone and prolactin rise, supporting tissue repair and immune function. When sleep is chronically short or disrupted, cortisol can remain elevated, potentially interfering with the hormonal signals that drive ovulation. Create a sleep sanctuary: cool room temperature, darkness, quiet. Consider a bedtime ritual: warm bath, reading, gentle stretching. Your partner can join you — male fertility is also affected by sleep quality, with studies linking poor sleep to reduced sperm quality.', source: 'DEVELOPMENT' as ContentSource, tags: ['sleep', 'hormones', 'cortisol', 'preconception', 'fertility'] },
    { stageKey: 'preg_week_2', category: 'NUTRITION_FEEDING', priority: 83, title: 'Antioxidants and Egg Quality: Eating for Cellular Health', summary: 'The egg that may become your baby has been maturing for months — antioxidants in your diet protect its cellular machinery.', content: 'Your eggs complete their final maturation over approximately 100 days before ovulation. During this time, they are vulnerable to oxidative stress — cellular damage from unstable molecules called free radicals. A diet rich in antioxidants helps protect egg quality. Key sources: berries, dark chocolate, pecans, and artichokes for a wide spectrum of antioxidants; vitamin C from citrus, bell peppers, and broccoli; vitamin E from almonds, sunflower seeds, and avocados; selenium from Brazil nuts — just one or two per day provides the recommended amount. Coenzyme Q10, found in organ meats, fatty fish, and whole grains, supports mitochondrial function in eggs and is a common supplement in fertility protocols. A colorful plate loaded with vegetables and fruits is your simplest and most delicious strategy.', source: 'DEVELOPMENT' as ContentSource, tags: ['antioxidants', 'egg quality', 'nutrition', 'oxidative stress', 'fertility diet'] },
    { stageKey: 'preg_week_2', category: 'PARENT_WELLBEING', priority: 81, title: 'Emotional Health During the Conception Journey', summary: 'Whether this is your first cycle trying or your tenth, the emotional landscape of trying to conceive deserves as much attention as the physical one.', content: 'Trying to conceive can bring unexpected emotional complexity — hope, disappointment, anxiety, jealousy, and joy can all coexist. It is normal for this to affect your mood, your relationship, and your sense of self. If you find yourself consumed by tracking apps and ovulation tests, consider taking one cycle off from intense tracking. Talk openly with your partner about how you are both feeling — different coping styles are common. Set boundaries around pregnancy announcements on social media if they trigger difficult feelings. It takes healthy couples up to a year to conceive — this is normal reproductive biology, not a failure. If you have been trying for over a year, or over 6 months if you are 35 or older, consult a fertility specialist. Your emotional wellbeing matters — consider therapy or a support group.', source: 'DEVELOPMENT' as ContentSource, tags: ['emotional health', 'TTC', 'conception', 'fertility journey', 'mental health'] },

    // ═══ preg_week_3 (had 1 card) ═══
    { stageKey: 'preg_week_3', category: 'GROWTH_HEALTH', priority: 87, title: 'The Fallopian Tube Journey: Your Embryo on the Move', summary: 'For 3 to 4 days after fertilization, your embryo travels through the fallopian tube — a critical passage where early cell division happens.', content: 'After fertilization in the ampulla (the outer third of the fallopian tube), the single-celled zygote begins its 3- to 4-day journey toward the uterus. It does not grow in size during this time but divides internally: 1 cell becomes 2, then 4, 8, 16 — each cell smaller than the last. The fallopian tube is not a passive corridor; it actively transports the embryo through gentle peristaltic contractions and the sweeping motion of tiny hair-like cilia lining the tube. If the tube is damaged or blocked — from prior infection, endometriosis, or surgery — the embryo may not reach the uterus, resulting in ectopic pregnancy or failure to implant. This is why fallopian tube health, assessed through hysterosalpingogram or laparoscopy, is part of some fertility evaluations.', source: 'CLINICAL' as ContentSource, tags: ['fallopian tube', 'fertilization', 'cell division', 'zygote', 'embryo transport'] },
    { stageKey: 'preg_week_3', category: 'NUTRITION_FEEDING', priority: 84, title: 'Progesterone-Rich Foods to Support Implantation', summary: 'While no diet guarantees implantation, certain nutrients support the hormonal environment that helps your embryo thrive.', content: 'After ovulation, progesterone rises to support the uterine lining and maintain a potential pregnancy. While your body produces progesterone naturally from the corpus luteum, certain nutrients support your endocrine system. Zinc, found in oysters, beef, pumpkin seeds, and chickpeas, supports hormone production. Vitamin B6 from poultry, fish, potatoes, and bananas supports progesterone balance. Healthy fats from avocados, olive oil, nuts, and seeds provide the cholesterol backbone from which all steroid hormones, including progesterone, are synthesized. Vitamin C from citrus, kiwi, and bell peppers supports corpus luteum function. Avoid extreme dieting or very low-calorie intake, which can disrupt hormone production. Continue taking your prenatal vitamin — the folate is now critical as the neural tube begins forming within days.', source: 'DEVELOPMENT' as ContentSource, tags: ['progesterone', 'implantation', 'zinc', 'vitamin B6', 'healthy fats'] },
    { stageKey: 'preg_week_3', category: 'SLEEP', priority: 78, title: 'The Two-Week Wait and Sleep Anxiety', summary: 'It is hard to sleep when your mind is spinning with what-ifs — practical strategies for rest during the wait.', content: 'The two-week wait — the days between ovulation and your expected period — is notorious for disrupted sleep. Racing thoughts about whether you might be pregnant, replaying every potential symptom, and the urge to test early can keep you awake. Try a brain dump before bed: write down all your swirling thoughts in a notebook, close it, and symbolically set them aside for the night. Progressive muscle relaxation — tensing and releasing each muscle group from toes to forehead — can quiet a restless body. Avoid pregnancy forums and symptom-googling in the hour before bed. If you wake at 3 AM with anxiety, get up briefly, have a small warm drink, and return to bed when you feel drowsy. One or two nights of poor sleep will not affect implantation — your embryo is remarkably resilient.', source: 'DEVELOPMENT' as ContentSource, tags: ['sleep', 'two-week wait', 'anxiety', 'insomnia', 'relaxation'] },
    { stageKey: 'preg_week_3', category: 'PARENT_WELLBEING', priority: 82, title: 'Mindfulness in the Waiting: Being Present When the Future Is Unknown', summary: 'Mindfulness does not mean pretending you do not care — it means fully experiencing the present while holding hope for the future.', content: 'The waiting period after ovulation can feel like suspended animation — your life on hold until you know. Mindfulness offers practical tools for navigating this uncertainty. A simple practice: when you notice your mind spiraling into the future, gently bring your attention back to your breath for five slow inhales and exhales. Another: the 5-4-3-2-1 grounding technique — name 5 things you can see, 4 you can touch, 3 you can hear, 2 you can smell, 1 you can taste. These do not fix the uncertainty, but they create moments of peace within it. Consider limiting pregnancy testing to the day of your missed period — testing early and seeing negatives day after day is emotionally exhausting. Plan something you look forward to around the time your period is due — a nice dinner, a movie, a walk with a friend — so the day holds something good regardless.', source: 'DEVELOPMENT' as ContentSource, tags: ['mindfulness', 'two-week wait', 'emotional health', 'grounding', 'self-compassion'] },

    // ═══ preg_week_6 (had 2 cards) ═══
    { stageKey: 'preg_week_6', category: 'SLEEP', priority: 82, title: 'First Trimester Fatigue: Why You Are So Exhausted', summary: 'Overwhelming exhaustion is one of the most common early pregnancy symptoms — your body is building an entirely new organ from scratch.', content: 'First trimester fatigue can be profound — the kind of tired where walking from bed to couch feels like a marathon. You are not lazy; your body is running a metabolic marathon invisibly. Your blood volume increases by about 50 percent during pregnancy, requiring your heart to pump significantly more blood. Your body is building the placenta — an entirely new organ — from scratch. Progesterone, which rises dramatically in early pregnancy, is a sedating hormone. Your metabolic rate increases, burning more energy even at rest. Listen to your body: nap when you can, even if it is just 20 minutes. Prioritize iron-rich foods to support increased blood production. Delegate non-essential tasks. This fatigue is temporary — most people experience a significant energy rebound in the second trimester around weeks 12 to 14.', source: 'CLINICAL' as ContentSource, tags: ['fatigue', 'first trimester', 'progesterone', 'energy', 'self-care'] },
    { stageKey: 'preg_week_6', category: 'NUTRITION_FEEDING', priority: 85, title: 'Managing Food Aversions: Eating When Nothing Sounds Good', summary: 'Food aversions affect up to 85 percent of pregnant people — here is how to nourish yourself when your favorite foods suddenly repulse you.', content: 'Food aversions, like morning sickness, are thought to be linked to rising hCG levels and heightened sense of smell — an evolutionary adaptation that may protect the developing embryo from potential toxins. Common aversions include meat, coffee, eggs, and strong-smelling vegetables. If your usual healthy staples now make you gag, try: bland carbohydrates (crackers, toast, rice, plain pasta), cold foods (smoothies, yogurt, cereal — cold foods have less aroma than hot), plant-based proteins (if meat is suddenly repulsive, try beans, lentils, tofu, or protein-fortified cereals), and small frequent meals rather than large ones. If you can only stomach a narrow range of foods right now, that is okay — focus on getting enough calories and continue your prenatal vitamin. Most food aversions resolve by the second trimester.', source: 'DEVELOPMENT' as ContentSource, tags: ['food aversions', 'nutrition', 'first trimester', 'hCG', 'pregnancy diet'] },

    // ═══ preg_week_7 (had 2 cards) ═══
    { stageKey: 'preg_week_7', category: 'SLEEP', priority: 81, title: 'Sleep Strategies for Nauseated Nights', summary: 'Nausea does not clock out at bedtime — but you can create conditions that help you rest even when you feel queasy.', content: 'Nighttime nausea can make falling and staying asleep a real challenge. Keep plain crackers or dry cereal on your nightstand — eating a small amount before getting out of bed can help stabilize blood sugar and reduce morning nausea. Ginger tea, with proven anti-nausea properties, can be sipped slowly in the evening. Eat a small protein-rich snack before bed — cheese, yogurt, or a handful of almonds — to prevent overnight blood sugar dips that can trigger nausea. Sleep slightly propped up with an extra pillow if acid reflux accompanies your nausea. Sea-Bands, acupressure wristbands available at most pharmacies, provide drug-free nausea relief for some people. If nausea prevents you from keeping down fluids, contact your provider — dehydration is a serious concern that may require IV fluids or medication.', source: 'DEVELOPMENT' as ContentSource, tags: ['nausea', 'sleep', 'morning sickness', 'ginger', 'first trimester'] },
    { stageKey: 'preg_week_7', category: 'PLAY_ACTIVITIES', priority: 76, title: 'Gentle Prenatal Yoga for the First Trimester', summary: 'Modified yoga can ease early pregnancy symptoms, reduce stress, and build the mind-body connection that serves you through birth.', content: 'Prenatal yoga in the first trimester focuses on gentle movement, breathing, and relaxation — not intense physical challenge. Cat-cow stretches on hands and knees relieve lower back tension and improve spinal mobility. Seated side bends gently open the ribcage. Pelvic tilts, done lying on your back briefly or standing, strengthen the core and alleviate back discomfort. Avoid deep twists that compress the abdomen, hot yoga, and poses that require lying flat on your back for extended periods, as the weight of the uterus can compress the vena cava after the first trimester. The most valuable practice you can develop now is conscious breathing — slow, deep belly breathing that signals safety to your nervous system. This breathing pattern is one of the most powerful tools you can bring into labor.', source: 'DEVELOPMENT' as ContentSource, tags: ['prenatal yoga', 'first trimester', 'gentle exercise', 'breathing', 'flexibility'] },

    // ═══ preg_week_9 (had 2 cards) ═══
    { stageKey: 'preg_week_9', category: 'SLEEP', priority: 83, title: 'The Pregnancy Pillow Decision: Do You Need One Now?', summary: 'You may not have a bump yet, but a pregnancy pillow can improve sleep alignment from the first trimester onward.', content: 'A pregnancy pillow is not just for the third trimester. Sleeping on your side — ideally the left side — is recommended throughout pregnancy to optimize blood flow to the placenta. Even in early pregnancy, a pillow between your knees aligns your hips and spine, reducing lower back strain. C-shaped pillows wrap around your entire body, supporting your head, belly, back, and knees simultaneously. U-shaped pillows provide support on both sides so you can roll over without rearranging. A simple wedge pillow under your belly can be sufficient for some. If you are not ready to invest, use regular pillows: one between your knees, one under your belly, one behind your back. The goal is spinal alignment and comfort. Start side-sleeping now to build the habit before your growing belly makes back-sleeping dangerous.', source: 'DEVELOPMENT' as ContentSource, tags: ['pregnancy pillow', 'sleep position', 'side sleeping', 'spine alignment', 'first trimester'] },
    { stageKey: 'preg_week_9', category: 'PARENT_WELLBEING', priority: 84, title: 'Pregnancy After Loss: Navigating Hope and Fear', summary: 'If you have experienced a previous pregnancy loss, the early weeks of a new pregnancy can bring joy tangled with anxiety — you are not alone.', content: 'Pregnancy after loss is a unique emotional experience that deserves acknowledgment and gentle support. It is completely normal to feel protective, anxious, and reluctant to celebrate or share news early. You may find yourself scrutinizing every symptom — or lack of symptoms — for signs of trouble. Consider finding a provider who understands your history and communicates clearly about what monitoring is appropriate. Some parents find reassurance in early ultrasounds and hCG draws; others prefer to wait. Both approaches are valid. Tell your provider about your history so they can offer appropriate care, and let them know what you need emotionally. Support groups for pregnancy after loss, both online and in-person, connect you with people who truly understand. Milestones like passing the point of your previous loss or reaching viability can bring up complicated feelings. There is no wrong way to navigate this — be gentle with yourself.', source: 'DEVELOPMENT' as ContentSource, tags: ['pregnancy after loss', 'miscarriage', 'anxiety', 'emotional health', 'support'] },

    // ═══ preg_week_13 (had 2 cards) ═══
    { stageKey: 'preg_week_13', category: 'GROWTH_HEALTH', priority: 88, title: 'Genetic Screening Options: NIPT, CVS, and Amniocentesis', summary: 'The first trimester opens a window for genetic screening — understanding your options helps you make informed choices.', content: 'Between weeks 10 and 13, your provider will discuss genetic screening options. Noninvasive prenatal testing (NIPT) analyzes fragments of fetal DNA circulating in your blood and can screen for trisomy 21, 18, 13, and sex chromosome conditions with high accuracy as early as week 10. Chorionic villus sampling (CVS), performed between weeks 10 and 13, samples placental tissue through the cervix or abdomen and provides diagnostic — not screening — results. Amniocentesis, available from week 15 onward, samples amniotic fluid. Both CVS and amnio carry a small risk of miscarriage. The choice to pursue screening, diagnostic testing, or neither is deeply personal. Some parents want all available information; others prefer to wait. There is no single right answer.', source: 'CLINICAL' as ContentSource, tags: ['NIPT', 'genetic screening', 'CVS', 'amniocentesis', 'trisomy'] },
    { stageKey: 'preg_week_13', category: 'NUTRITION_FEEDING', priority: 83, title: 'Second Trimester Nutrition: What Changes Now', summary: 'As nausea subsides and energy returns, the second trimester is your window to focus on nutrient-dense eating.', content: 'With morning sickness often easing by week 13, many pregnant people find they can finally eat a wider variety of foods. Calorie needs increase modestly — about 340 extra calories per day in the second trimester, roughly equivalent to a sandwich or a yogurt parfait. Protein needs rise to about 71 grams daily to support rapid fetal tissue growth. Iron needs increase dramatically — your blood volume is expanding and your baby is building iron stores for the first six months of life. Calcium requirements remain high — 1000 mg daily — for your baby\'s bone development. Omega-3 fatty acids, especially DHA, are critical for brain and eye development. If fish is not your preference, an algae-based DHA supplement is a good option. This is also the trimester when some people develop pica — cravings for non-food items like ice or starch — which can indicate iron deficiency.', source: 'DEVELOPMENT' as ContentSource, tags: ['second trimester nutrition', 'protein', 'iron', 'calcium', 'DHA'] },
    { stageKey: 'preg_week_13', category: 'SLEEP', priority: 80, title: 'Second Trimester Sleep: The Sweet Spot', summary: 'For many, the second trimester brings the best sleep of the entire pregnancy — here is how to maximize it.', content: 'The second trimester is often the most comfortable for sleep: nausea has typically resolved, energy is rebounding, and the physical discomforts of late pregnancy have not yet arrived. Take advantage of this window. Establish a consistent sleep schedule — going to bed and waking at the same time every day, including weekends. Create a bedtime ritual: warm bath, reading, gentle stretching. Continue side-sleeping even if back-sleeping still feels comfortable — building the habit now will serve you when your growing belly makes it medically necessary. If you snore or wake gasping, tell your provider — pregnancy increases the risk of sleep apnea. Avoid screens for an hour before bed. If you wake during the night, do not check your phone — the light resets your circadian rhythm. Enjoy this window of relative rest — the third trimester brings new sleep challenges.', source: 'DEVELOPMENT' as ContentSource, tags: ['sleep', 'second trimester', 'sleep hygiene', 'side sleeping', 'energy'] },

    // ═══ preg_week_15 (had 1 card) ═══
    { stageKey: 'preg_week_15', category: 'GROWTH_HEALTH', priority: 87, title: 'Your Baby at 15 Weeks: Proportional and Active', summary: 'At 15 weeks, your baby\'s body is catching up to the head — legs are now longer than arms, and movement is becoming coordinated.', content: 'At 15 weeks, your fetus measures about 10 centimeters (4 inches) crown to rump and weighs approximately 70 grams (2.5 ounces). The body proportions are becoming more human-like — the legs now outgrow the arms, and the head, while still large, is no longer disproportionately so. Your baby is practicing complex movements: bending elbows and knees, making fists, sucking the thumb. The skin is so thin and translucent that blood vessels are visible through it. Fine hair called lanugo covers the body, helping hold the vernix caseosa, a waxy protective coating, in place. The bones are hardening, a process called ossification, which will continue throughout pregnancy. If you have an ultrasound, you may see your baby hiccupping or changing positions. Your baby can now sense light, even through your abdominal wall, and may move away from bright light directed at your belly.', source: 'CLINICAL' as ContentSource, tags: ['fetal development', '15 weeks', 'ossification', 'lanugo', 'second trimester'] },
    { stageKey: 'preg_week_15', category: 'DEVELOPMENT', priority: 85, title: 'Your Baby\'s Senses Are Awakening', summary: 'By 15 weeks, your baby\'s sensory systems are coming online — taste buds are forming and the ears are moving into their final position.', content: 'The second trimester is when your baby\'s sensory development accelerates. By week 15, taste buds are forming on the tongue, and the baby begins swallowing amniotic fluid, which carries flavors from your diet. Research suggests that babies exposed to varied flavors through amniotic fluid are more accepting of those flavors after birth. The structures of the inner ear are ossifying, and while hearing is not yet fully functional, the auditory system is developing rapidly — by week 18, your baby will begin to hear your heartbeat and voice. The eyes, which started as dark spots weeks ago, are now moving toward the front of the face, and the optic nerves are forming. Your baby\'s brain is growing at an astonishing rate — approximately 250,000 neurons are being produced every minute during mid-pregnancy.', source: 'DEVELOPMENT' as ContentSource, tags: ['sensory development', 'taste buds', 'fetal hearing', 'brain development', 'second trimester'] },
    { stageKey: 'preg_week_15', category: 'NUTRITION_FEEDING', priority: 83, title: 'Omega-3s and Your Baby\'s Brain: What the Science Says', summary: 'DHA is the most abundant omega-3 in the brain — your baby\'s developing brain depends on your dietary intake.', content: 'Docosahexaenoic acid (DHA) is a long-chain omega-3 fatty acid that accumulates in the fetal brain and retina during the second half of pregnancy. The fetal brain grows most rapidly from mid-pregnancy through the second year of life, and DHA is a critical structural component of brain cell membranes. Best dietary sources: low-mercury fatty fish including wild salmon, sardines, Atlantic mackerel, and herring — 2 to 3 servings per week. For plant-based and vegan diets: algae oil supplements provide DHA directly without fish. Flaxseed, chia seeds, and walnuts provide alpha-linolenic acid (ALA), which the body can convert to DHA, though the conversion rate is limited. Many prenatal vitamins now include DHA. Adequate DHA intake during pregnancy is associated with modest improvements in cognitive development and may reduce the risk of preterm birth.', source: 'DEVELOPMENT' as ContentSource, tags: ['DHA', 'omega-3', 'brain development', 'fish oil', 'nutrition'] },

    // ═══ preg_week_16 (had 2 cards) ═══
    { stageKey: 'preg_week_16', category: 'GROWTH_HEALTH', priority: 85, title: 'Amniotic Fluid: Your Baby\'s Protective Ocean', summary: 'Amniotic fluid does far more than cushion — it regulates temperature, enables movement, and supports lung development.', content: 'Amniotic fluid is a remarkable substance that serves multiple critical functions. It cushions the fetus from external pressure and impact. It maintains a consistent temperature. It allows the baby to move freely, which is essential for musculoskeletal development. The baby breathes amniotic fluid in and out, which is critical for lung development and maturation. It also contains antibacterial properties that help protect against infection. In early pregnancy, amniotic fluid is produced primarily by the mother\'s blood plasma passing through the fetal membranes. From about week 16 onward, the baby\'s kidneys begin producing urine, which becomes the primary source of amniotic fluid — yes, your baby is floating in and swallowing their own urine, which is sterile and normal. The volume increases throughout pregnancy, peaking around 800 to 1000 milliliters at 34 to 36 weeks.', source: 'CLINICAL' as ContentSource, tags: ['amniotic fluid', 'fetal development', 'oligohydramnios', 'polyhydramnios', 'second trimester'] },
    { stageKey: 'preg_week_16', category: 'PLAY_ACTIVITIES', priority: 78, title: 'Music and Your Developing Baby', summary: 'Your baby can begin hearing around week 18 — but starting a musical practice now builds a habit you will both enjoy.', content: 'By around 18 to 20 weeks, your baby\'s auditory system is developed enough to detect sounds from outside the womb. Low-frequency sounds — like your voice, your partner\'s voice, and bass notes in music — travel through your body best. Research shows that newborns recognize and are calmed by voices and music they heard regularly during the third trimester. Consider creating a lullaby playlist now. Sing the same one or two songs each evening before bed — after birth, these songs can become powerful soothing cues. If you play an instrument, your baby can feel the vibrations. The quality of sound your baby hears is somewhat muffled and low-pass-filtered, similar to listening to music underwater. What matters most is not perfection but consistency and love.', source: 'DEVELOPMENT' as ContentSource, tags: ['music', 'fetal hearing', 'bonding', 'lullaby', 'prenatal stimulation'] },

    // ═══ preg_week_19 (had 1 card) ═══
    { stageKey: 'preg_week_19', category: 'GROWTH_HEALTH', priority: 90, title: 'The Anatomy Scan Window Opens', summary: 'Between 18 and 22 weeks, you will have your most detailed ultrasound — your baby is now large enough for comprehensive evaluation.', content: 'The mid-pregnancy anatomy scan, typically performed between 18 and 22 weeks, systematically examines your baby from head to toe. The sonographer will measure the head circumference, abdominal circumference, femur length, and check the brain structures, facial profile, spine, heart chambers and outflow tracts, stomach, kidneys, bladder, umbilical cord vessels, placenta location, amniotic fluid volume, and cervical length. Your baby\'s sex can usually be determined at this scan if you choose to know. The scan takes 30 to 60 minutes depending on your baby\'s position. If your baby is not cooperating, you may be asked to walk, change positions, or return for additional views. Most anatomy scans reveal normal findings. If anything uncertain is seen, your provider will discuss the finding and any recommended follow-up with you.', source: 'CLINICAL' as ContentSource, tags: ['anatomy scan', 'ultrasound', 'fetal anatomy', '20-week', 'second trimester'] },
    { stageKey: 'preg_week_19', category: 'SLEEP', priority: 81, title: 'Leg Cramps: The Nighttime Disruptor', summary: 'Sudden, painful leg cramps often strike during the second trimester at night — here is why they happen and how to prevent them.', content: 'Leg cramps, particularly in the calves, affect up to 50 percent of pregnant people, often striking at night during the second and third trimesters. The exact cause is not fully understood but may involve compression of blood vessels by the growing uterus, changes in calcium and magnesium metabolism, and fatigue from carrying extra weight. Prevention strategies: stay hydrated throughout the day, stretch your calves before bed — flex your foot upward, not pointed — and consider magnesium supplementation after discussing with your provider. When a cramp strikes, immediately flex your foot upward (dorsiflex), pointing your toes toward your shin — this stretches the cramping calf muscle. Do not point your toes — this contracts the muscle and worsens the cramp. Massaging the muscle and applying heat or a warm bath before bed can also help. Most leg cramps resolve after delivery.', source: 'CLINICAL' as ContentSource, tags: ['leg cramps', 'sleep', 'second trimester', 'magnesium', 'calf stretches'] },
    { stageKey: 'preg_week_19', category: 'PARENT_WELLBEING', priority: 84, title: 'Preparing Your Relationship for the Baby', summary: 'A new baby transforms your partnership — intentional conversations now build the foundation for a strong postpartum relationship.', content: 'The transition to parenthood is one of the most significant shifts a relationship will ever experience. Research consistently shows that relationship satisfaction often dips after the birth of a first child — not because people stop loving each other, but because the demands of newborn care leave little time and energy for the relationship. This is normal and navigable with intentional effort. Start talking now about how you will divide nighttime feedings, household tasks, and the mental load of baby care. Discuss your expectations and fears openly. Acknowledge that both partners will be exhausted and that patience and generosity will be needed. Consider scheduling regular check-ins — 15 minutes when you are both awake and not holding the baby — to reconnect. Your partnership is the foundation on which your family is built; nurturing it is not selfish, it is essential.', source: 'DEVELOPMENT' as ContentSource, tags: ['relationships', 'partnership', 'postpartum', 'communication', 'family'] },

    // ═══ preg_week_21 (had 2 cards) ═══
    { stageKey: 'preg_week_21', category: 'DEVELOPMENT', priority: 86, title: 'Your Baby\'s Movement Patterns: What Is Normal', summary: 'By 21 weeks, most parents have felt movement — understanding normal patterns helps you know your baby.', content: 'Fetal movement patterns vary widely from baby to baby. Some babies are active in the morning, others in the evening. Some have bursts of activity followed by quiet periods. By 21 weeks, you may notice your baby responds to your activity — many babies are more active when you are resting and quieter when you are moving, as your motion rocks them to sleep. It is not necessary to count kicks formally this early, but paying attention to your baby\'s general patterns is beneficial. A sudden decrease in fetal movement is always worth calling your provider about — do not wait until the next day or your next appointment. Common myths: a very active baby does NOT mean a hyperactive child, and hiccups, while normal, do not replace the need to feel other movements. If you have an anterior placenta, you may feel movement later and less distinctly — this is normal.', source: 'DEVELOPMENT' as ContentSource, tags: ['fetal movement', 'kick counting', 'anterior placenta', 'baby patterns', 'second trimester'] },
    { stageKey: 'preg_week_21', category: 'NUTRITION_FEEDING', priority: 82, title: 'Iron in Pregnancy: Why You Need More and How to Get It', summary: 'Your blood volume has increased by nearly 50 percent — iron is the critical nutrient supporting this massive physiological expansion.', content: 'Iron needs nearly double during pregnancy, from about 18 mg to 27 mg daily. This increased demand supports your expanding blood volume and your baby\'s iron storage, which must last through the first 4 to 6 months of life since breast milk is naturally low in iron. Heme iron from animal sources — lean red meat, poultry, fish — is best absorbed. Non-heme iron from plant sources — lentils, spinach, fortified cereals, tofu — is better absorbed when paired with vitamin C. Try lentils with lemon juice, spinach salad with bell peppers, or fortified cereal with strawberries. Avoid drinking tea or coffee with iron-rich meals — tannins inhibit absorption. Iron deficiency anemia affects approximately 15 to 25 percent of pregnant people and can cause fatigue, weakness, shortness of breath, and increased risk of preterm birth and low birth weight. Your provider monitors hemoglobin at prenatal visits — if levels are low, supplementation is effective and important.', source: 'CLINICAL' as ContentSource, tags: ['iron', 'anemia', 'nutrition', 'blood volume', 'supplementation'] },

    // ═══ preg_week_22 (had 2 cards) ═══
    { stageKey: 'preg_week_22', category: 'GROWTH_HEALTH', priority: 87, title: 'Viability: A Significant Milestone', summary: 'Around 22 to 24 weeks, your baby reaches the threshold of viability — the earliest point at which survival outside the womb is possible.', content: 'Viability is the gestational age at which a fetus has a reasonable chance of survival outside the womb with intensive medical support. This threshold is generally considered to be around 22 to 24 weeks, though survival rates and long-term outcomes vary significantly. At 22 weeks, with maximal intensive care, survival rates are approximately 30 to 40 percent in highly specialized centers that offer active treatment. By 24 weeks, survival increases to about 55 to 70 percent. Each additional week significantly improves outcomes. Reaching viability is an emotional milestone for many parents — a relief that your baby now has a chance outside the womb, even if you hope they stay for many more weeks. Continue taking care of yourself: every additional day and week of pregnancy improves your baby\'s development, particularly brain and lung maturation, which continue rapidly through the third trimester.', source: 'CLINICAL' as ContentSource, tags: ['viability', 'preterm birth', 'NICU', 'fetal development', '22 weeks'] },
    { stageKey: 'preg_week_22', category: 'PLAY_ACTIVITIES', priority: 77, title: 'Reading to Your Baby in Utero', summary: 'Your voice is the most important sound in your baby\'s world — reading aloud builds connection and language familiarity.', content: 'Research suggests that newborns can recognize and prefer the rhythm and melody of a story read aloud repeatedly during the third trimester. Reading to your baby before birth is less about the words and more about the sound of your voice — the rhythm, tone, and emotional quality. Choose books you genuinely enjoy — your baby will not understand the words but will absorb the cadence. Picture books with rhythmic language like Goodnight Moon or The Very Hungry Caterpillar work well. Your partner or other family members can read too — building their own voice recognition. This practice also establishes a reading routine you can continue after birth, which supports language development, bonding, and the habit of reading for pleasure. There is no right or wrong way — simply talking, singing, and reading to your belly is a gift to your developing baby.', source: 'DEVELOPMENT' as ContentSource, tags: ['reading', 'fetal hearing', 'bonding', 'language development', 'voice recognition'] },

    // ═══ preg_week_23 (had 1 card) ═══
    { stageKey: 'preg_week_23', category: 'GROWTH_HEALTH', priority: 86, title: 'Your Baby at 23 Weeks: A Miniature Newborn', summary: 'At 23 weeks, your baby looks increasingly like a tiny newborn — complete with eyebrows, eyelashes, and a sense of balance.', content: 'At 23 weeks, your baby weighs about 500 grams (1.1 pounds) and measures approximately 28 centimeters (11 inches) from head to toe. The face is now fully formed with eyebrows, eyelashes, and distinct facial features. The inner ear, including the vestibular system that controls balance, is developed — your baby can now sense position changes as you move. The pancreas, essential for insulin production, is developing. The lungs are producing surfactant, though not yet in sufficient quantities for unassisted breathing. The skin is wrinkled and reddish, with visible blood vessels, as the baby has not yet accumulated significant fat. Vernix caseosa, the waxy protective coating, covers the skin. Your baby now has regular sleep-wake cycles — you may notice patterns in their activity. If born at this stage, a baby would require months of intensive care but has a real chance of survival.', source: 'CLINICAL' as ContentSource, tags: ['fetal development', '23 weeks', 'surfactant', 'sleep-wake cycles', 'viability'] },
    { stageKey: 'preg_week_23', category: 'DEVELOPMENT', priority: 83, title: 'Your Baby\'s Developing Brain: The Second Trimester Surge', summary: 'Your baby\'s brain is adding neurons at up to 250,000 per minute — the second trimester is a period of explosive brain growth.', content: 'The second trimester represents the peak of neurogenesis — the creation of new neurons. Your baby\'s brain is producing neurons at an extraordinary rate, and these neurons must migrate to their correct locations, differentiate into specialized types, and begin forming connections called synapses. The cerebral cortex, the folded outer layer of the brain responsible for higher thinking, begins to develop its characteristic ridges and grooves. Myelination — the insulation of nerve fibers that dramatically speeds signal transmission — begins. This is why adequate nutrition, particularly DHA, iron, iodine, and choline, is so critical during mid-pregnancy. Avoid alcohol completely — even moderate drinking during the second trimester is associated with measurable effects on brain development. This is also why preterm birth, even in the late preterm period, can affect neurodevelopment — the brain is meant to develop in the protected uterine environment.', source: 'DEVELOPMENT' as ContentSource, tags: ['brain development', 'neurogenesis', 'myelination', 'synapses', 'second trimester'] },

    // ═══ preg_week_25 (had 1 card) ═══
    { stageKey: 'preg_week_25', category: 'GROWTH_HEALTH', priority: 88, title: 'Your Baby at 25 Weeks: Rapid Weight Gain Begins', summary: 'Starting around 24 to 26 weeks, your baby enters a phase of rapid weight gain — adding baby fat and preparing for life outside.', content: 'From about 24 weeks onward, your baby shifts from primarily lengthening to adding significant weight. At 25 weeks, your baby weighs about 660 grams (1.5 pounds). Over the next 15 weeks, they will more than quadruple that weight. This weight gain includes the accumulation of subcutaneous fat, which will smooth the wrinkled skin, provide insulation for temperature regulation after birth, and serve as an energy reserve. The lungs continue maturing, with more surfactant produced each week. The nostrils, which have been plugged until now, begin to open. The capillaries — the tiniest blood vessels — are forming, giving the skin an increasingly pink color. Your baby may respond to familiar voices and loud noises with movement. If you play music or sing, your baby may respond — or may simply continue sleeping, which is also perfectly normal.', source: 'CLINICAL' as ContentSource, tags: ['fetal development', 'weight gain', '25 weeks', 'subcutaneous fat', 'third trimester preparation'] },
    { stageKey: 'preg_week_25', category: 'SLEEP', priority: 80, title: 'Heartburn at Night: Causes and Relief', summary: 'As your uterus expands, it pushes on your stomach — heartburn often worsens at night when lying down.', content: 'Heartburn, or acid reflux, affects up to 80 percent of pregnant people, particularly in the second half of pregnancy. Progesterone relaxes the lower esophageal sphincter — the valve that keeps stomach acid from flowing back up — while the growing uterus presses upward on the stomach. Nighttime is often worst because lying flat removes gravity\'s help in keeping acid down. Relief strategies: eat smaller meals, avoid eating within 2 to 3 hours of bedtime, and identify trigger foods (common culprits include spicy foods, citrus, tomato products, chocolate, and caffeine). Sleep with your upper body elevated — a wedge pillow or raising the head of your bed 10 to 15 centimeters. Over-the-counter antacids containing calcium carbonate are generally considered safe during pregnancy, but check with your provider before using H2 blockers or proton pump inhibitors. Most heartburn resolves dramatically the moment you give birth.', source: 'CLINICAL' as ContentSource, tags: ['heartburn', 'acid reflux', 'sleep', 'progesterone', 'third trimester'] },

    // ═══ preg_week_26 (had 2 cards) ═══
    { stageKey: 'preg_week_26', category: 'GROWTH_HEALTH', priority: 85, title: 'Blood Pressure Monitoring: Why It Matters Now', summary: 'Blood pressure typically dips in mid-pregnancy then rises in the third trimester — knowing your baseline helps detect concerning changes early.', content: 'Blood pressure naturally decreases during the first and second trimesters due to progesterone relaxing blood vessel walls. It typically reaches its lowest point around 20 to 24 weeks, then gradually returns toward pre-pregnancy levels in the third trimester. At every prenatal visit, your provider checks your blood pressure to screen for hypertensive disorders of pregnancy, including gestational hypertension and preeclampsia. Preeclampsia affects 5 to 8 percent of pregnancies and is characterized by high blood pressure and signs of organ damage, often involving the kidneys. Warning signs include severe headache that does not respond to acetaminophen, vision changes (spots, blurring, flashing lights), upper right abdominal pain, sudden swelling of face and hands, and rapid weight gain from fluid retention. These symptoms warrant immediate medical attention — do not wait for your next scheduled appointment.', source: 'CLINICAL' as ContentSource, tags: ['blood pressure', 'preeclampsia', 'gestational hypertension', 'prenatal monitoring', 'warning signs'] },
    { stageKey: 'preg_week_26', category: 'PARENT_WELLBEING', priority: 84, title: 'The Mental Load of Pregnancy: Naming and Managing It', summary: 'The invisible work of pregnancy — researching, planning, preparing — is real cognitive labor deserving of acknowledgment.', content: 'The mental load of pregnancy extends far beyond the physical experience. You may be researching car seats, comparing pediatricians, reading birth books, managing your registry, planning parental leave, organizing the nursery, fielding unsolicited advice, and processing a constant stream of information — all while growing a human. This cognitive labor is work, even if it does not produce a visible output. It is completely normal to feel overwhelmed. Naming this mental load helps — acknowledging to yourself and your partner that this is real labor, not just excitement or anxiety. Delegate research tasks to your partner: they can research car seats, compare daycares, or schedule hospital tours. Set boundaries around information consumption — you do not need to read every pregnancy book or follow every Instagram expert. If you find yourself unable to stop researching or consumed by worry, consider talking to a perinatal therapist.', source: 'DEVELOPMENT' as ContentSource, tags: ['mental load', 'cognitive labor', 'partner support', 'emotional health', 'pregnancy planning'] },

    // ═══ preg_week_27 (had 1 card) ═══
    { stageKey: 'preg_week_27', category: 'GROWTH_HEALTH', priority: 89, title: 'Glucose Screening Preparation and What Results Mean', summary: 'Your glucose screening is coming up — understanding the test reduces anxiety and helps you prepare.', content: 'The glucose challenge test, typically scheduled between 24 and 28 weeks, screens for gestational diabetes. You will drink a sweet solution containing 50 grams of glucose — it tastes like very sweet flat soda, served chilled to improve palatability. One hour later, your blood is drawn. Fasting is usually not required. If your one-hour result is elevated — typically above 130 or 140 milligrams per deciliter — you will need the three-hour glucose tolerance test, which requires an 8- to 14-hour fast. For the three-hour test, fasting blood is drawn, you drink a 100-gram glucose solution, and blood is drawn at one, two, and three hours. Elevated results on two or more of these draws indicates gestational diabetes. A diagnosis can feel frightening, but it is manageable. Treatment typically involves dietary changes, blood sugar monitoring, and exercise; some people require medication or insulin. Outcomes with treatment are excellent.', source: 'CLINICAL' as ContentSource, tags: ['glucose screening', 'gestational diabetes', 'GDM', 'glucose tolerance', 'prenatal testing'] },
    { stageKey: 'preg_week_27', category: 'DEVELOPMENT', priority: 85, title: 'Your Baby\'s Lungs: Preparing for That First Breath', summary: 'From week 24 onward, your baby\'s lungs are producing surfactant — the substance that makes breathing possible after birth.', content: 'Lung development is one of the last organ systems to mature. By about 24 weeks, type II pneumocytes — specialized lung cells — begin producing surfactant, a soapy substance composed of lipids and proteins that reduces surface tension in the alveoli, the tiny air sacs where gas exchange occurs. Without enough surfactant, the alveoli would collapse with every exhalation — this is respiratory distress syndrome, the primary breathing challenge for premature infants. Surfactant production increases throughout the third trimester, with adequate levels for unassisted breathing typically reached around 34 to 36 weeks. If preterm birth is anticipated before 34 weeks, your provider may administer corticosteroid injections — betamethasone — which cross the placenta and accelerate fetal lung maturity. These steroids significantly reduce the risk of respiratory distress syndrome, intraventricular hemorrhage, and necrotizing enterocolitis in premature infants.', source: 'DEVELOPMENT' as ContentSource, tags: ['lung development', 'surfactant', 'respiratory distress', 'preterm birth', 'corticosteroids'] },

    // ═══ preg_week_29 (had 1 card) ═══
    { stageKey: 'preg_week_29', category: 'GROWTH_HEALTH', priority: 89, title: 'Your Baby at 29 Weeks: Eyes Wide Open', summary: 'Your baby can now open and close their eyes, distinguish light from dark, and may be settling into the head-down position.', content: 'At 29 weeks, your baby weighs about 1.15 kilograms (2.5 pounds) and measures around 38 centimeters (15 inches). A significant development now: your baby\'s eyes can open and close, and the irises can respond to light. The pupils can dilate and constrict. Your baby can distinguish between light and dark filtering through your abdominal wall. The central nervous system has matured enough to begin regulating body temperature — though your baby still relies on the placenta and your body for heat. The bone marrow has taken over red blood cell production from the liver and spleen. Your baby is now strong enough that kicks may be visible from the outside — you may see your belly ripple or bulge with a well-placed foot. Your baby is likely settling into a head-down position in preparation for birth, though this may not happen for several more weeks. The head is still soft — the skull bones remain unfused to allow molding during birth.', source: 'CLINICAL' as ContentSource, tags: ['fetal development', '29 weeks', 'eye development', 'head-down', 'third trimester'] },
    { stageKey: 'preg_week_29', category: 'PARENT_WELLBEING', priority: 86, title: 'Writing Your Birth Preferences: A Practical Guide', summary: 'A birth preferences document is a communication tool — here is a structured approach that is clear, concise, and collaborative.', content: 'A birth preferences plan communicates your hopes to your care team while acknowledging the unpredictability of birth. Structure it by stage: labor environment (who you want present, lighting, music, mobility), pain management (your preferences for unmedicated coping, nitrous oxide, epidural, or to decide in the moment), labor and pushing (positions, coached vs spontaneous pushing, your preference on episiotomy), cesarean birth (if needed, preferences for clear drape, skin-to-skin in OR, partner presence), immediate postpartum (delayed cord clamping, immediate skin-to-skin, newborn procedures, feeding intentions). Use language like "I prefer", "if possible", "I would like to discuss" — never "I demand" or "under no circumstances". Birth is unpredictable and a collaborative tone keeps the team on your side. Keep it to one page. Bring multiple copies. Review it with your provider before labor.', source: 'GENERAL' as ContentSource, tags: ['birth plan', 'birth preferences', 'communication', 'advocacy', 'third trimester'] },

    // ═══ preg_week_31 (had 1 card) ═══
    { stageKey: 'preg_week_31', category: 'GROWTH_HEALTH', priority: 88, title: 'Your Baby at 31 Weeks: Packing on the Pounds', summary: 'Your baby now gains about 200 grams (half a pound) per week — most of it in the form of adorable baby fat.', content: 'At 31 weeks, your baby weighs approximately 1.5 kilograms (3.3 pounds) and measures about 41 centimeters (16 inches). The rapid weight gain phase is in full swing — your baby will gain approximately 200 grams per week from now until birth. This weight is primarily subcutaneous fat, which transforms the wrinkled, translucent appearance into the plump newborn look. The fat serves critical functions: insulation, energy storage, and the cute round cheeks that make breastfeeding mechanically efficient. The central nervous system continues maturing — your baby now has periods of REM sleep, which is essential for brain development. Your baby\'s bones are fully formed but remain soft and pliable, particularly the skull, which will compress slightly during birth. Your baby is now urinating about 500 milliliters daily into the amniotic fluid, which is constantly recycled as they swallow it.', source: 'CLINICAL' as ContentSource, tags: ['fetal development', 'weight gain', '31 weeks', 'body fat', 'third trimester'] },
    { stageKey: 'preg_week_31', category: 'SLEEP', priority: 82, title: 'Third Trimester Insomnia: You Are Not Alone', summary: 'Up to 75 percent of pregnant people report insomnia in the third trimester — a combination of physical discomfort and anticipatory anxiety.', content: 'Third trimester insomnia is extremely common and has multiple causes: difficulty finding a comfortable position, frequent urination, heartburn, leg cramps, back pain, restless legs syndrome, and the anxious excitement about birth and parenthood. Acknowledge that some sleep disruption is inevitable and do not add self-criticism about poor sleep to your list of stressors. Practical strategies: maintain a consistent bedtime routine, use multiple pillows to create a comfortable nest, avoid screens for an hour before bed, limit fluids in the two hours before bedtime, and treat heartburn and leg cramps proactively. If you cannot sleep after 20 to 30 minutes, get up and do something calming in low light — reading, gentle stretching, listening to a meditation — until you feel drowsy. Napping during the day, if possible, can help offset nighttime sleep loss. This too shall pass — newborn sleep is different, but postpartum sleep is often deeper and more restorative.', source: 'DEVELOPMENT' as ContentSource, tags: ['insomnia', 'sleep', 'third trimester', 'restless legs', 'anxiety'] },

    // ═══ preg_week_33 (had 2 cards) ═══
    { stageKey: 'preg_week_33', category: 'GROWTH_HEALTH', priority: 87, title: 'Your Baby at 33 Weeks: Almost Ready', summary: 'If born now, your baby would likely need minimal support — but every extra week inside still makes a meaningful difference.', content: 'At 33 weeks, your baby weighs approximately 1.9 kilograms (4.2 pounds) and measures about 43 centimeters (17 inches). Babies born at 33 weeks — called moderate to late preterm — have excellent survival rates exceeding 98 percent with modern neonatal care. They typically need some support: temperature regulation may be immature, feeding coordination may not be fully developed, and they may spend time in a special care nursery rather than a full NICU. However, each additional week inside the womb still significantly improves outcomes. Weeks 34 to 36 are when the lungs finish maturing and the suck-swallow-breathe coordination for feeding solidifies. Your amniotic fluid volume peaks around this time, then gradually decreases until birth. Your baby\'s immune system is receiving antibodies from you through the placenta — this passive immunity provides protection for the first months after birth.', source: 'CLINICAL' as ContentSource, tags: ['fetal development', '33 weeks', 'late preterm', 'lung maturity', 'passive immunity'] },
    { stageKey: 'preg_week_33', category: 'NUTRITION_FEEDING', priority: 84, title: 'Hydration in the Third Trimester: Why Water Matters More Than Ever', summary: 'Your blood volume is at its peak, amniotic fluid needs replenishing, and dehydration can trigger contractions — drink up.', content: 'Adequate hydration is critical throughout pregnancy but particularly in the third trimester when blood volume peaks at about 50 percent above pre-pregnancy levels. Dehydration can trigger Braxton Hicks contractions and, in some cases, preterm labor. Aim for 8 to 12 glasses of water daily, more in hot weather or with exercise. Your urine should be pale yellow — dark urine signals dehydration. If plain water is unappealing, try: infused water with cucumber, lemon, or berries, herbal teas (check safety — ginger, peppermint, and rooibos are generally considered safe), milk or fortified plant milks, and water-rich foods like watermelon, cucumber, oranges, and soups. Limit caffeine to 200 milligrams daily. Energy drinks, sugary sodas, and excessive fruit juice provide empty calories. If you are experiencing swelling in your feet and ankles, drinking adequate water actually helps — your body retains fluid when it thinks water is scarce.', source: 'DEVELOPMENT' as ContentSource, tags: ['hydration', 'water', 'third trimester', 'Braxton Hicks', 'swelling'] },

    // ═══ preg_week_35 (had 1 card) ═══
    { stageKey: 'preg_week_35', category: 'GROWTH_HEALTH', priority: 92, title: 'Your Baby at 35 Weeks: Term Is Around the Corner', summary: 'At 35 weeks, your baby is almost fully mature — the lungs are nearly ready and the brain is in a final growth spurt.', content: 'At 35 weeks, your baby weighs approximately 2.4 kilograms (5.3 pounds) and measures about 46 centimeters (18 inches). The lungs are producing surfactant at adequate levels for most babies — though some 35-weekers, called late preterm, still need transient respiratory support. The brain is in a final growth spurt, increasing in weight by about one-third between 35 and 40 weeks. The skull bones remain soft and separated, with the fontanelles — the soft spots — remaining open to allow the head to mold during birth. Your baby\'s testes have descended into the scrotum if male, and the labia have formed if female. The vernix caseosa is thickening. If your baby is in a breech position now, there is still a chance they will turn spontaneously, though the likelihood decreases as space becomes tighter. Your provider may discuss external cephalic version — a procedure to manually turn the baby — between 36 and 38 weeks.', source: 'CLINICAL' as ContentSource, tags: ['fetal development', '35 weeks', 'late preterm', 'brain growth', 'breech'] },
    { stageKey: 'preg_week_35', category: 'PARENT_WELLBEING', priority: 89, title: 'Making Decisions About Pain Management in Labor', summary: 'There is no single right way to manage labor pain — understanding your options empowers you to make informed choices in real time.', content: 'Pain management during labor exists on a spectrum, and your preferences may change in the moment — that is completely valid. Unmedicated approaches include hydrotherapy (warm water in shower or tub), movement and position changes, massage and counterpressure, breathing techniques, visualization, and TENS machines. Nitrous oxide, a self-administered gas you inhale during contractions, provides relaxation without eliminating sensation — it wears off within minutes. Systemic opioids like fentanyl or morphine can take the edge off but cross the placenta and may cause newborn drowsiness. Epidural analgesia provides the most complete pain relief by blocking sensation from the waist down while allowing you to remain awake and alert. It does not increase the cesarean rate, though it may prolong the pushing phase. You can combine approaches, change your mind at any time, or start with one approach and add another. Pain management is not a test of character — it is a tool to help you navigate an intense experience.', source: 'GENERAL' as ContentSource, tags: ['pain management', 'epidural', 'labor', 'unmedicated birth', 'nitrous oxide'] },

    // ═══ preg_week_37 (had 2 cards) ═══
    { stageKey: 'preg_week_37', category: 'GROWTH_HEALTH', priority: 94, title: 'Your Baby at 37 Weeks: Welcome to Early Term', summary: 'At 37 weeks, your baby is officially early term — lungs should be mature, and you could go into labor any day now.', content: 'At 37 weeks, your baby is considered early term — a full-term pregnancy is defined as 39 to 40 weeks. Births between 37 and 38 weeks are generally safe, though babies born at 37 weeks have slightly higher rates of respiratory issues, feeding difficulties, and NICU admissions compared to those born at 39 weeks. This is why elective inductions and scheduled cesareans are recommended at 39 weeks or later unless medically indicated. Your baby now weighs around 2.9 kilograms (6.4 pounds) and measures about 48 centimeters (19 inches). The lungs should be producing adequate surfactant for unassisted breathing. The baby has developed a layer of insulating fat, and the skin is smooth and pink. Your baby is now practicing breathing movements, sucking, and grasping — all skills they will need immediately after birth. The umbilical cord, your baby\'s lifeline for nine months, is about 55 centimeters long and has transported nutrients and oxygen while removing waste. Labor could begin at any time now — review the signs of labor and ensure your bag is packed.', source: 'CLINICAL' as ContentSource, tags: ['37 weeks', 'early term', 'full term', 'lung maturity', 'labor preparation'] },
    { stageKey: 'preg_week_37', category: 'SLEEP', priority: 83, title: 'Sleeping in Late Pregnancy: The Final Stretch', summary: 'Between the belly, the bathroom trips, and the anticipation, sleep has never been harder — realistic strategies for the final weeks.', content: 'Late pregnancy sleep is a unique challenge. Between the physical discomfort of a full-term belly, the bladder as a trampoline, and the mental anticipation of labor and parenthood, it is a perfect storm. Accept that perfect sleep is unlikely and focus on what is possible: naps during the day, resting in a recliner if lying flat is uncomfortable, and prioritizing rest over sleep — simply lying quietly with your eyes closed provides some restorative benefit. If you cannot sleep, do not lie in bed stressing about not sleeping — get up briefly. This is temporary. Soon you will have a newborn, and while newborn sleep is frequent and fragmented, many parents find the quality of postpartum sleep, when it comes, much better than late pregnancy sleep. Your body returns to you. Your lungs can expand fully. You can sleep on your back or stomach. Hang in there — you are so close.', source: 'DEVELOPMENT' as ContentSource, tags: ['sleep', 'late pregnancy', 'final weeks', 'rest', 'postpartum anticipation'] },

    // ═══ preg_week_39 (had 1 card) ═══
    { stageKey: 'preg_week_39', category: 'GROWTH_HEALTH', priority: 95, title: 'Your Baby at 39 Weeks: Full Term and Ready', summary: 'Congratulations — your baby is officially full term. Every system is prepared for life outside the womb.', content: 'At 39 weeks, your baby is full term and weighs approximately 3.2 to 3.4 kilograms (7 to 7.5 pounds) on average, measuring about 50 centimeters (20 inches). The lungs are fully mature with adequate surfactant. The brain has completed its final growth spurt and now weighs about 350 grams — it will continue developing rapidly through the first years of life. The skull bones remain unfused, with the fontanelles allowing the head to mold during birth. Your baby\'s immune system has received antibodies from you, providing protection for the first months after birth. The vernix caseosa is primarily absorbed, with some remaining in skin folds. Your baby is now positioned low in your pelvis, which may bring pelvic pressure and the urge to urinate frequently — this is called lightening or engagement. Labor could begin at any moment. Trust your body. Trust your team. You have grown an entire human from two cells. You are ready.', source: 'GENERAL' as ContentSource, tags: ['39 weeks', 'full term', 'labor readiness', 'fetal development', 'birth'] },
    { stageKey: 'preg_week_39', category: 'PARENT_WELLBEING', priority: 91, title: 'The Final Days: Trust, Patience, and Surrender', summary: 'The days leading up to labor are a unique liminal space — you are about to meet your baby, and waiting can feel interminable.', content: 'These final days of pregnancy are unlike any other time in your life. You are on the threshold of meeting your baby, and everything — your body, your home, your heart — is preparing. It is normal to feel done, to want this baby out right now, to be tired of your body and the waiting. It is also normal to feel nervous, to wonder if you are ready, to feel sadness about pregnancy ending. All of these feelings can coexist. Try to fill these days with gentle, joyful activities: a movie with your partner, a meal at your favorite restaurant, a long phone call with a friend. Rest. Hydrate. Eat. Say yes to help. Your body knows what to do — it has been preparing for this moment since conception. When labor begins, you will meet it with every resource you have. Until then, let yourself be held by the love and support around you. You do not need to be productive in these final days. You just need to be.', source: 'DEVELOPMENT' as ContentSource, tags: ['final days', 'labor anticipation', 'emotional preparation', 'trust', 'self-compassion'] },
  ];

  for (const card of cards) {
    await prisma.expertAdviceCard.upsert({
      where: { id: `seed_advice_${card.stageKey}_${card.title.replace(/[^a-zA-Z0-9]/g, '_').substring(0, 30)}` },
      update: card,
      create: { id: `seed_advice_${card.stageKey}_${card.title.replace(/[^a-zA-Z0-9]/g, '_').substring(0, 30)}`, ...card },
    });
  }

  console.log(`Seeded ${cards.length} pregnancy fill-in advice cards (batch 4 pregnancy)`);
  return cards.length;
}
